  // let fatia_texto = middle_name.split(" ")
  // console.log(fatia_texto)
  // console.table(fatia_texto)

  let ful_name = "Maria Clara de Jose"
  let array_string = full_name.split(" ")
  let name = arry_string[0]
  console.log(name)
  console.log(array_string[4 - 1])
  //let last_name = array_string[]


  return (
    <div className="App">
      <header className="App-header">
        <img src={logo} className="App-logo" alt="logo" />
        <p>
        Òla {name} {}
        </p>
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn React
        </a>
      </header>
    </div>
  );
}

export default App;
